export interface AdviceCardProps {
  title: string;
  href: string;
  excerpt: string;
  readTime: string;
  tag: string;
  image: string;
}

export function AdviceCard({
  title,
  href,
  excerpt,
  readTime,
  tag,
  image,
}: AdviceCardProps) {
  return (
    <article className="group flex flex-col">
      {/* Photo */}
      <Link
        href={href}
        className="relative overflow-hidden rounded-sm bg-sand aspect-[16/10] block mb-5"
        aria-label={`Lees artikel: ${title}`}
        tabIndex={-1}
      >
        <Image
          src={image}
          alt={title}
          fill
          className="object-cover object-center transition-transform duration-700 group-hover:scale-105"
          unoptimized
          sizes="(max-width: 768px) 100vw, 33vw"
        />
        <div className="absolute inset-0 bg-brown/10 group-hover:bg-brown/20 transition-colors duration-300" />
      </Link>

      {/* Meta */}
      <div className="flex items-center gap-3 mb-3">
        <span className="font-sans text-[10px] uppercase tracking-widest text-copper font-medium">
          {tag}
        </span>
        <span className="w-px h-3 bg-border" aria-hidden="true" />
        <span className="font-sans text-[10px] text-brown-muted">{readTime}</span>
      </div>

      {/* Title */}
      <Link href={href}>
        <h3 className="font-serif text-xl md:text-2xl font-light text-brown leading-snug hover:text-sage transition-colors mb-3 text-balance">
          {title}
        </h3>
      </Link>

      {/* Excerpt */}
      <p className="font-sans text-sm text-brown-muted leading-relaxed mb-4 flex-1 line-clamp-3">
        {excerpt}
      </p>

      {/* CTA */}
      <Link
        href={href}
        className="inline-flex items-center gap-2 font-sans text-sm text-brown-muted hover:text-brown transition-colors group/link self-start pb-0.5 border-b border-border hover:border-brown"
      >
        Lees meer
        <ArrowRight className="w-3.5 h-3.5 transition-transform group-hover/link:translate-x-0.5" />
      </Link>
    </article>
  );
}

"use client";

import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { ArrowRight } from "lucide-react";

export function NewsletterCta() {
  const [email, setEmail] = useState("");
  const [submitted, setSubmitted] = useState(false);

  function handleSubmit(e: React.FormEvent<HTMLFormElement>) {
    e.preventDefault();
    if (!email) return;
    setSubmitted(true);
  }

  return (
    <section
      aria-label="Nieuwsbrief"
      className="py-20 md:py-24 bg-sand border-t border-border"
    >
      <div className="container mx-auto px-4 md:px-6">
        <div className="max-w-2xl mx-auto text-center">
          {/* Eyebrow */}
          <p className="font-sans text-xs tracking-[0.2em] uppercase text-copper mb-4 font-medium">
            Nieuwsbrief
          </p>

          {/* Heading */}
          <h2 className="font-serif text-3xl md:text-4xl text-brown font-light leading-tight text-balance mb-4">
            Slaapadvies in je inbox
          </h2>
          <p className="font-sans text-base text-brown-muted leading-relaxed mb-8 text-balance">
            Geen spam, alleen kennis. Praktische slaaptips, productnieuws en
            advies van specialisten — een paar keer per maand.
          </p>

          {/* Form */}
          {!submitted ? (
            <form
              onSubmit={handleSubmit}
              className="flex flex-col sm:flex-row gap-3 max-w-md mx-auto"
              noValidate
            >
              <label htmlFor="newsletter-email" className="sr-only">
                E-mailadres
              </label>
              <Input
                id="newsletter-email"
                type="email"
                placeholder="jouw@email.nl"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                required
                className="flex-1 bg-background border-border font-sans text-sm text-brown placeholder:text-brown-muted/60 rounded-sm h-11 focus-visible:ring-sage"
                aria-label="E-mailadres voor nieuwsbrief"
              />
              <Button
                type="submit"
                className="bg-copper hover:bg-copper/90 text-primary-foreground font-sans text-sm tracking-wide h-11 px-6 rounded-sm gap-2 flex-shrink-0"
              >
                Aanmelden
                <ArrowRight className="w-4 h-4" />
              </Button>
            </form>
          ) : (
            <div className="max-w-md mx-auto py-4">
              <p className="font-serif text-xl text-brown font-light">
                Dank voor je aanmelding.
              </p>
              <p className="font-sans text-sm text-brown-muted mt-2">
                Je ontvangt binnenkort jouw eerste slaaptips van Rupose.
              </p>
            </div>
          )}

          {/* Fine print */}
          {!submitted && (
            <p className="font-sans text-xs text-brown-muted/60 mt-4">
